module top_module(
	input clk,
	input reset,
	output [7:0] count);reg [7:0] johnson;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
	if (reset)
		johnson <= 8'b00000000;
	else
		johnson <= {johnson[6:0], ~johnson[7]};

assign count = johnson;

endmodule
